channelPosts.js.content:
import { InputFile } from "grammy";
import { detectFirstContract } from "../utils/contracts.js";
import { fetchTokenDetails } from "../services/tokenLookup.js";
import { fetchChartImage } from "../services/chartService.js";
import { formatTokenSummary } from "../utils/messageFormatter.js";
import { logError, logInfo, logWarn, safeErr } from "../utils/logger.js";

const inFlightKeys = new Set();

export function registerChannelHandlers(bot) {
  bot.on(["channel_post", "edited_channel_post"], async (ctx) => {
    const post = ctx.update.channel_post || ctx.update.edited_channel_post;
    if (!post) return;

    const chatId = post.chat?.id;
    const messageId = post.message_id;
    const text = [post.text || "", post.caption || ""].filter(Boolean).join("\n");

    logInfo("[channel] scan start", {
      chatId,
      messageId,
      edited: Boolean(ctx.update.edited_channel_post)
    });

    const match = detectFirstContract(text);
    logInfo("[channel] scan result", {
      chatId,
      messageId,
      detected: Boolean(match)
    });

    if (!match) {
      return;
    }

    const lockKey = `${chatId}:${messageId}:${match.address}`;
    if (inFlightKeys.has(lockKey)) {
      return;
    }

    inFlightKeys.add(lockKey);

    try {
      const token = await fetchTokenDetails(match.address);
      logInfo("[token] lookup success", {
        contract: match.address,
        symbol: token.symbol,
        chain: token.chain
      });

      const caption = formatTokenSummary(token);

      try {
        const chartBuffer = await fetchChartImage(token);
        logInfo("[chart] fetch success", {
          contract: token.address,
          bytes: chartBuffer.length
        });

        try {
          await ctx.api.sendPhoto(chatId, new InputFile(chartBuffer, "chart.png"), {
            caption,
            reply_parameters: { message_id: messageId }
          });
        } catch (err) {
          logWarn("[send] photo failed, fallback to text", {
            contract: token.address,
            error: safeErr(err)
          });
          await sendTextFallback(ctx, chatId, messageId, caption, token.chartUrl);
        }
      } catch (err) {
        logWarn("[chart] fetch failure", {
          contract: token.address,
          error: safeErr(err)
        });
        await sendTextFallback(ctx, chatId, messageId, caption, token.chartUrl);
      }
    } catch (err) {
      const error = safeErr(err);
      logError("[token] lookup failure", {
        contract: match.address,
        error
      });

      if (shouldReplyOnLookupFailure(text, error)) {
        try {
          await ctx.api.sendMessage(chatId, "I found a contract-looking address, but token data is unavailable right now.", {
            reply_parameters: { message_id: messageId }
          });
        } catch (sendErr) {
          logWarn("[send] failure notice failed", {
            contract: match.address,
            error: safeErr(sendErr)
          });
        }
      }
    } finally {
      inFlightKeys.delete(lockKey);
    }
  });
}

async function sendTextFallback(ctx, chatId, messageId, caption, chartUrl) {
  const text = chartUrl ? `${caption}\nChart link: ${chartUrl}` : caption;
  logInfo("[send] using text fallback", {
    chatId,
    messageId,
    hasChartUrl: Boolean(chartUrl)
  });
  await ctx.api.sendMessage(chatId, text, {
    reply_parameters: { message_id: messageId }
  });
}

function shouldReplyOnLookupFailure(sourceText, error) {
  const lower = String(sourceText || "").toLowerCase();
  if (lower.includes("0x") && !String(error).toLowerCase().includes("unsupported")) {
    return true;
  }
  return false;
}

index.js.content:
import "dotenv/config";
import { run } from "@grammyjs/runner";

function safeErr(err) {
  return err?.response?.data?.error?.message || err?.response?.data?.message || err?.message || String(err);
}

process.on("unhandledRejection", (err) => {
  console.error("[process] unhandledRejection", { error: safeErr(err) });
  process.exit(1);
});

process.on("uncaughtException", (err) => {
  console.error("[process] uncaughtException", { error: safeErr(err) });
  process.exit(1);
});

let runnerHandle = null;
let restarting = false;

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function boot() {
  try {
    const [{ cfg }, { createBot }, { registerCommands }, { safeErr: helperSafeErr }, { startMemoryLogLoop }] = await Promise.all([
      import("./lib/config.js"),
      import("./bot.js"),
      import("./commands/loader.js"),
      import("./utils/logger.js"),
      import("./utils/memory.js")
    ]);

    console.log("[boot] start", {
      TELEGRAM_BOT_TOKEN: Boolean(cfg.TELEGRAM_BOT_TOKEN),
      TOKEN_API_BASE_URL: Boolean(cfg.TOKEN_API_BASE_URL),
      CHART_IMAGE_BASE_URL: Boolean(cfg.CHART_IMAGE_BASE_URL)
    });

    if (!cfg.TELEGRAM_BOT_TOKEN) {
      console.error("[boot] TELEGRAM_BOT_TOKEN missing. Add it to .env or Render environment and redeploy.");
      process.exit(1);
    }

    const bot = createBot(cfg.TELEGRAM_BOT_TOKEN);
    await bot.init();
    await registerCommands(bot);

    try {
      await bot.api.setMyCommands([
        { command: "start", description: "Welcome and overview" },
        { command: "help", description: "Usage and channel setup" }
      ]);
    } catch (err) {
      console.warn("[boot] setMyCommands failed", { error: helperSafeErr(err) });
    }

    bot.catch((err) => {
      console.error("[bot] middleware error", {
        error: helperSafeErr(err?.error || err)
      });
    });

    startMemoryLogLoop();

    let backoffMs = 2000;

    while (true) {
      try {
        console.log("[polling] cycle start", { backoffMs });
        await bot.api.deleteWebhook({ drop_pending_updates: true });
        console.log("[polling] webhook cleared");

        runnerHandle = run(bot, {
          runner: {
            fetch: {
              allowed_updates: ["message", "channel_post", "edited_channel_post"]
            }
          }
        });

        console.log("[polling] started");
        await runnerHandle.task();
        console.warn("[polling] runner stopped unexpectedly");
      } catch (err) {
        const message = helperSafeErr(err);
        console.error("[polling] failure", { error: message });

        if (String(message).includes("409") || String(message).toLowerCase().includes("conflict")) {
          console.warn("[polling] conflict detected, backing off", { backoffMs });
        }
      } finally {
        try {
          if (runnerHandle) {
            runnerHandle.stop();
          }
        } catch {}
        runnerHandle = null;
      }

      if (restarting) {
        return;
      }

      await sleep(backoffMs);
      backoffMs = Math.min(backoffMs === 2000 ? 5000 : backoffMs * 2, 20000);
    }
  } catch (err) {
    console.error("[boot] error", {
      error: safeErr(err),
      code: err?.code || ""
    });
    process.exit(1);
  }
}

boot();

ai.js.content:
function trimSlash(u) {
  u = String(u || "");
  while (u.endsWith("/")) u = u.slice(0, -1);
  return u;
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function safeRead(r) {
  const text = await r.text();
  let json = null;
  try { json = JSON.parse(text); } catch {}
  return { text, json };
}

function notConfigured(message) {
  return { ok: false, status: 412, json: null, text: "", error: message };
}

function withTimeout(ms) {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), ms);
  return { ctrl, clear: () => clearTimeout(t) };
}

function pickTimeout(cfg) {
  const v = Number(cfg?.AI_TIMEOUT_MS || cfg?.AI_TIMEOUT || 20000);
  return Number.isFinite(v) && v > 0 ? v : 20000;
}

function pickModel(cfg, override) {
  const m = String(override || cfg?.AI_MODEL || "").trim();
  return m || undefined;
}

function isRetryableStatus(status) {
  // 408: request timeout, 429: rate, 500/502/503/504 transient
  return status === 408 || status === 429 || status === 500 || status === 502 || status === 503 || status === 504;
}

function redact(s) {
  s = String(s || "");
  if (s.length <= 400) return s;
  return s.slice(0, 400) + "…";
}

function web3Mode(cfg) {
  const m = String(cfg?.WEB3_CHAT_MODE || "auto").trim().toLowerCase();
  return (m === "on" || m === "off" || m === "auto") ? m : "auto";
}

async function aiGet(cfg, path, opts = {}) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  const DEBUG = String(cfg?.AI_DEBUG || "") === "1";
  if (!base || !key) return notConfigured("AI_NOT_CONFIGURED (missing COOKMYBOTS_AI_ENDPOINT/COOKMYBOTS_AI_KEY)");

  const timeoutMs = Number(opts.timeoutMs || pickTimeout(cfg));
  const url = base + String(path || "");

  const { ctrl, clear } = withTimeout(timeoutMs);
  try {
    if (DEBUG) console.log("[aiGet] ->", url);
    const r = await fetch(url, { method: "GET", headers: { Authorization: "Bearer " + key }, signal: ctrl.signal });
    const { text, json } = await safeRead(r);
    if (!r.ok) {
      const err = json?.error || json?.message || text || "AI_ERROR";
      return { ok: false, status: r.status, json, text, error: String(err) };
    }
    return { ok: true, status: r.status, json, text, error: null };
  } catch (e) {
    const msg = e?.name === "AbortError" ? "AI_TIMEOUT" : (e?.message || "AI_NETWORK_ERROR");
    return { ok: false, status: e?.name === "AbortError" ? 408 : 0, json: null, text: "", error: String(msg) };
  } finally {
    clear();
  }
}

async function routeChat(cfg, userText, systemHint) {
  // Uses the normal gateway /chat as a fast classifier.
  // Returns: "web3" | "normal"
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  if (!base || !key) return "normal";

  const timeoutMs = Math.min(8000, pickTimeout(cfg));
  const { ctrl, clear } = withTimeout(timeoutMs);

  const sys = [
    "You are a routing classifier for a bot.",
    "Decide if the user's message should go to a Web3 specialist model (ChainGPT) or a normal general AI model.",
    "",
    "Return ONLY valid JSON:",
    '{"route":"web3"}',
    "or",
    '{"route":"normal"}',
    "",
    "Route to web3 if the user asks about: crypto, tokens, Solidity, smart contracts, audits, DeFi, NFTs, wallets, chains, bridges, gas, DEXs, on-chain tools or anything related to blockchain.",
    "Otherwise route to normal.",
    "",
    "Extra context (bot/system hint):",
    String(systemHint || "").slice(0, 800),
  ].join("
");

  try {
    const r = await fetch(base + "/chat", {
      method: "POST",
      headers: {
        Authorization: "Bearer " + key,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        messages: [
          { role: "system", content: sys },
          { role: "user", content: String(userText || "").slice(0, 2000) },
        ],
        model: pickModel(cfg, ""), // let gateway default or AI_MODEL
        meta: { purpose: "route" },
      }),
      signal: ctrl.signal,
    });

    const { text, json } = await safeRead(r);
    if (!r.ok) return "normal";

    // Try common shapes: gateway might return {text} or OpenAI-like {choices}
    const out =
      (json && (json.text || json.message)) ||
      (json && json.choices && json.choices[0] && json.choices[0].message && json.choices[0].message.content) ||
      text ||
      "";

    const raw = String(out || "").trim();

    // Parse JSON safely
    try {
      const obj = JSON.parse(raw);
      const route = String(obj?.route || "").toLowerCase();
      return route === "web3" ? "web3" : "normal";
    } catch {
      // If model returned non-JSON, fallback to normal
      return "normal";
    }
  } catch {
    return "normal";
  } finally {
    clear();
  }
}

/**
 * Low-level gateway call.
 * Always returns: { ok, status, json, text, error }
 * - json is parsed response body (if JSON)
 * - error is a short string for logs/UI
 */
export async function aiCall(cfg, path, body, opts = {}) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  const DEBUG = String(cfg?.AI_DEBUG || "") === "1";

  if (!base || !key) return notConfigured("AI_NOT_CONFIGURED (missing COOKMYBOTS_AI_ENDPOINT/COOKMYBOTS_AI_KEY)");

  const timeoutMs = Number(opts.timeoutMs || pickTimeout(cfg));
  const retries = Number.isFinite(opts.retries) ? Number(opts.retries) : 1; // default 1 retry
  const backoffMs = Number.isFinite(opts.backoffMs) ? Number(opts.backoffMs) : 750;

  const url = base + String(path || "");
  const started = Date.now();

  let attempt = 0;
  while (true) {
    attempt++;

    const { ctrl, clear } = withTimeout(timeoutMs);
    try {
      if (DEBUG) console.log("[aiCall] ->", url, { attempt, timeoutMs });

      const r = await fetch(url, {
        method: "POST",
        headers: {
          Authorization: "Bearer " + key,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(body || {}),
        signal: ctrl.signal,
      });

      const { text, json } = await safeRead(r);

      if (!r.ok) {
        const err = json?.error || json?.message || text || "AI_ERROR";
        const out = { ok: false, status: r.status, json, text, error: String(err) };

        if (DEBUG) {
          const ms = Date.now() - started;
          console.warn("[aiCall] <- fail", { status: r.status, ms, attempt, err: redact(err) });
        }

        // Retry transient errors
        if (attempt <= retries && isRetryableStatus(r.status)) {
          await sleep(backoffMs * attempt);
          continue;
        }

        return out;
      }

      if (DEBUG) {
        const ms = Date.now() - started;
        console.log("[aiCall] <- ok", { status: r.status, ms, attempt });
      }

      return { ok: true, status: r.status, json, text, error: null };
    } catch (e) {
      const msg = e?.name === "AbortError" ? "AI_TIMEOUT" : (e?.message || "AI_NETWORK_ERROR");
      const out = { ok: false, status: e?.name === "AbortError" ? 408 : 0, json: null, text: "", error: String(msg) };

      if (DEBUG) {
        const ms = Date.now() - started;
        console.warn("[aiCall] <- exception", { ms, attempt, err: redact(msg) });
      }

      // Retry network/timeout issues (status 0/408)
      if (attempt <= retries) {
        await sleep(backoffMs * attempt);
        continue;
      }

      return out;
    } finally {
      clear();
    }
  }
}

/**
 * CHAT
 * Backward compatible:
 * 1) aiChat(cfg, "hello", { model, meta, system })
 * 2) aiChat(cfg, { messages:[...], model, meta })
 *
 * Returns: { ok, status, json, text, error }
 */
export async function aiChat(cfg, input, opts = {}) {
  // Signature (cfg, { messages, model, meta })
  if (input && typeof input === "object" && Array.isArray(input.messages)) {
    const model = pickModel(cfg, input.model);
    return aiCall(cfg, "/chat", {
      messages: input.messages,
      model,
      meta: input.meta || undefined,
    }, opts);
  }

  // Signature (cfg, "prompt")
  const userText = String(input || "");
  const system = String(opts.system || "You are a helpful assistant.");
  const model = pickModel(cfg, opts.model);

  return aiCall(cfg, "/chat", {
    messages: [
      { role: "system", content: system },
      { role: "user", content: userText },
    ],
    model,
    meta: opts.meta || undefined,
  }, opts);
}

